#include <stdio.h>
#include <stdbool.h>

// Function to check if a number is even
bool isEven(int num) {
    return num % 2 == 0;
}

// Function to check if a number is odd
bool isOdd(int num) {
    return num % 2 != 0;
}

// Function to simulate the game
bool simulateGame(int k, int piles[][101], int choice) {
    // Simulate the game for the given choice
    for (int i = 0; i < k; i++) {
        // Check if the current pile has any elements
        if (piles[i][0] > 0) {
            // Check if the current pile has a winning move
            for (int j = 1; j <= piles[i][0]; j++) {
                if ((choice == 0 && isEven(piles[i][j])) || (choice == 1 && isOdd(piles[i][j]))) {
                    // Remove the chosen number and all larger numbers from the pile
                    int newCount = 0;
                    for (int l = 1; l <= piles[i][0]; l++) {
                        if (piles[i][l] < piles[i][j]) {
                            piles[i][newCount + 1] = piles[i][l];
                            newCount++;
                        }
                    }
                    piles[i][0] = newCount;
                    // Recursively simulate the game for the opponent's turn
                    if (!simulateGame(k, piles, 1 - choice)) {
                        return true;
                    }
                    // Backtrack and restore the pile
                    piles[i][0] = newCount + 1;
                    for (int l = 1; l <= newCount; l++) {
                        piles[i][l + 1] = piles[i][l];
                    }
                    piles[i][1] = piles[i][j];
                }
            }
        }
    }
    // If no winning move is found, return false
    return false;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int k;
        scanf("%d", &k);
        int piles[k][101];
        for (int i = 0; i < k; i++) {
            scanf("%d", &piles[i][0]);
            for (int j = 1; j <= piles[i][0]; j++) {
                scanf("%d", &piles[i][j]);
            }
        }
        // Simulate the game for both 'EVEN' and 'ODD' choices
        if (simulateGame(k, piles, 0)) {
            printf("EVEN\n");
        } else if (simulateGame(k, piles, 1)) {
            printf("ODD\n");
        } else {
            printf("DON'T PLAY\n");
        }
    }
    return 0;
}

