import java.util.Scanner;
public class Main {
    // Function to check if a number is even
    public static boolean isEven(int num) {
        return num % 2 == 0;
    }

    // Function to check if a number is odd
    public static boolean isOdd(int num) {
        return num % 2 != 0;
    }

    // Function to simulate the game
    public static boolean simulateGame(int[][] piles, int choice) {
        // Simulate the game for the given choice
        for (int i = 0; i < piles.length; i++) {
            // Check if the current pile has any elements
            if (piles[i].length > 0) {
                // Check if the current pile has a winning move
                for (int j = 0; j < piles[i].length; j++) {
                    if ((choice == 0 && isEven(piles[i][j])) || (choice == 1 && isOdd(piles[i][j]))) {
                        // Remove the chosen number and all larger numbers from the pile
                        int[] newPile = new int[piles[i].length - 1];
                        int newIndex = 0;
                        for (int l = 0; l < piles[i].length; l++) {
                            if (piles[i][l] < piles[i][j]) {
                                newPile[newIndex++] = piles[i][l];
                            }
                        }
                        piles[i] = newPile;
                        // Recursively simulate the game for the opponent's turn
                        if (!simulateGame(piles, 1 - choice)) {
                            return true;
                        }
                        // Backtrack and restore the pile
                        piles[i] = new int[piles[i].length + 1];
                        piles[i][0] = piles[i].length;
                        for (int l = 0; l < newPile.length; l++) {
                            piles[i][l + 1] = newPile[l];
                        }
                        piles[i][0] = piles[i].length;
                    }
                }
            }
        }
        // If no winning move is found, return false
        return false;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int k = scanner.nextInt();
            int[][] piles = new int[k][];
            for (int i = 0; i < k; i++) {
                int ni = scanner.nextInt();
                piles[i] = new int[ni + 1];
                piles[i][0] = ni;
                for (int j = 1; j <= ni; j++) {
                    piles[i][j] = scanner.nextInt();
                }
            }
            // Simulate the game for both 'EVEN' and 'ODD' choices
            if (simulateGame(piles, 0)) {
                System.out.println("EVEN");
            } else if (simulateGame(piles, 1)) {
                System.out.println("ODD");
            } else {
                System.out.println("DON'T PLAY");
            }
        }
    }
}

